onFilesSelected:
{{
  (async () => {
    const files = FilePicker_Scrap.files;
    if (!files || files.length === 0) return;

    const excelData = files[0].data;
    if (!excelData || excelData.length === 0) {
        showAlert("❌ File trống! / 文件为空!", "error");
        return;
    }

    try {
        showAlert("⏳ Đang xử lý dữ liệu... / 正在处理数据...", "info");
        let count = 0;

        for (let row of excelData) {
            // Lấy trực tiếp từ cột tool_code
            if (!row.tool_code) continue; 

            // 1. Lưu vào Danh sách phế (Gọi đúng Insert_Full_Logs và truyền đúng tham số)
            await Insert_Full_Logs.run({
                xuong: row.workshop || '',
                code: String(row.tool_code).trim(),
                name: row.tool_name || '',
                unit: row.unit || '',
                qty: Number(row.quantity) || 0,
                emp: row.requester || '',
                loai: row.material_type || '',
                vitri: row.usage_location || '',
                nguyennhan: row.scrap_reason || '',
                nguoiduyet: row.approve || '',
                trangthai: 'Pending',
                ghichu: 'Nhập từ file / 从文件导入'
            });

            // 2. Ghi vào Lịch sử (Gọi đúng Insert_All_In_One và truyền Tên)
            await Insert_All_In_One.run({
                code: String(row.tool_code).trim(),
                name: row.tool_name || '', 
                qty: Number(row.quantity) || 0,
                trang_thai: 'NHAP_PHE',
                emp: row.requester || 'SYSTEM',
                ghi_chu: 'Nhập từ file / 从文件导入: ' + (row.scrap_reason || '')
            });

            count++;
        }

        if (count > 0) {
            showAlert(`✅ Đã nhập thành công ${count} dòng! / 成功导入 ${count} 行!`, "success");
            // Load lại bảng
            await Get_Scrap_List.run(); 
            await Get_LS_Phe.run();     
        } else {
            showAlert("⚠️ Không có dữ liệu hợp lệ! / 没有有效数据!", "warning");
        }

        resetWidget('FilePicker_Scrap', true);

    } catch (err) {
        showAlert("❌ Lỗi / 错误: " + err.message, "error");
        console.error(err);
    }
  })();
}}
